+  <body>
+    <pre id="out">starting</pre>
+    <script type="module">
+      // Exercises the custom rule engine: a regex rule (credit-card-ish
+      // digit grouping) + a function rule (JIRA-style ticket reference)
+      // in both batch and streaming paths. Verifies:
+      //   - rule spans land with source="rule" and the declared severity
