+      //   - rule spans use the rule's marker by default
+      //   - streaming output equals batch output
+
+      import { PrivacyFilter } from "/packages/textsift-core/dist/index.js";
+
+      const $out = document.getElementById("out");
+      const log = (m) => { $out.textContent += "\n" + m; };
+
+      const TEXT =
+        "Card 4111-1111-1111-1111 charged today. " +
+        "Linked to ticket PROJ-4821 in our tracker. " +
+        "Backup card: 5500 0000 0000 0004 expires soon.";
+
+      const rules = [
+        {
+          label: "CREDIT_CARD",
+          severity: "block",
+          marker: "[CARD]",
+          // 4 groups of 4 digits, separated by space or hyphen.
+          pattern: /\b(?:\d{4}[\s-]){3}\d{4}\b/g,
+        },
+        {
+          label: "JIRA_TICKET",
+          severity: "warn",
+          marker: "[TICKET]",
+          match: (text) => {
+            const out = [];
