+        `  ticketSpans=${result.ticketSpanCount} (severity=${JSON.stringify(result.ticketSeverity)})\n` +
+        `  cardRedacted=${result.cardRedacted} ticketRedacted=${result.ticketRedacted} cardLeaked=${result.cardLeaked}\n` +
